import { NextResponse } from "next/server";
import pg from "pg";

export const runtime = "nodejs";

const { Pool } = pg;

function getPool() {
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  return new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
}

/**
 * Get all payment gateways
 */
export async function GET() {
  const pool = getPool();
  try {
    const { rows } = await pool.query(`
      SELECT 
        id, provider, display_name, enabled, mode, priority, config,
        secret_key_env, publishable_key_env, created_at, updated_at
      FROM admin_payment_gateways
      ORDER BY priority, display_name
    `);

    // Check which env vars are configured
    const gateways = rows.map((g: any) => ({
      ...g,
      secretKeyConfigured: g.secret_key_env ? !!process.env[g.secret_key_env] : null,
      publishableKeyConfigured: g.publishable_key_env ? !!process.env[g.publishable_key_env] : null,
    }));

    return NextResponse.json({ gateways });
  } catch (err: any) {
    // Table might not exist yet
    if (err.message?.includes("does not exist")) {
      return NextResponse.json({ gateways: [], needsMigration: true });
    }
    console.error("[admin/settings/gateways] GET Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

/**
 * Create or update a payment gateway
 */
export async function POST(req: Request) {
  const body = await req.json();
  const {
    id,
    provider,
    displayName,
    enabled,
    mode,
    priority,
    config,
  } = body;

  if (!provider) {
    return NextResponse.json({ error: "provider required" }, { status: 400 });
  }

  const pool = getPool();
  try {
    let result;

    if (id) {
      // Update existing
      result = await pool.query(`
        UPDATE admin_payment_gateways SET
          display_name = COALESCE($2, display_name),
          enabled = COALESCE($3, enabled),
          mode = COALESCE($4, mode),
          priority = COALESCE($5, priority),
          config = COALESCE($6, config),
          updated_at = NOW()
        WHERE id = $1
        RETURNING *
      `, [id, displayName, enabled, mode, priority, config ? JSON.stringify(config) : null]);
    } else {
      // Insert new
      result = await pool.query(`
        INSERT INTO admin_payment_gateways (provider, display_name, enabled, mode, priority, config)
        VALUES ($1, $2, $3, $4, $5, $6)
        ON CONFLICT (provider) DO UPDATE SET
          display_name = COALESCE(EXCLUDED.display_name, admin_payment_gateways.display_name),
          enabled = COALESCE(EXCLUDED.enabled, admin_payment_gateways.enabled),
          mode = COALESCE(EXCLUDED.mode, admin_payment_gateways.mode),
          priority = COALESCE(EXCLUDED.priority, admin_payment_gateways.priority),
          config = COALESCE(EXCLUDED.config, admin_payment_gateways.config),
          updated_at = NOW()
        RETURNING *
      `, [provider, displayName || provider, enabled ?? false, mode || 'test', priority || 0, config ? JSON.stringify(config) : '{}']);
    }

    // Log the change
    await pool.query(`
      INSERT INTO admin_logs (log_type, details)
      VALUES ('gateway_update', $1)
    `, [JSON.stringify({ provider, enabled, mode })]);

    return NextResponse.json({ ok: true, gateway: result.rows[0] });
  } catch (err: any) {
    console.error("[admin/settings/gateways] POST Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

/**
 * Delete a payment gateway
 */
export async function DELETE(req: Request) {
  const url = new URL(req.url);
  const id = url.searchParams.get("id");

  if (!id) {
    return NextResponse.json({ error: "id required" }, { status: 400 });
  }

  // Don't allow deleting stripe
  const pool = getPool();
  try {
    const { rows: check } = await pool.query(
      `SELECT provider FROM admin_payment_gateways WHERE id = $1`,
      [id]
    );

    if (check[0]?.provider === 'stripe') {
      return NextResponse.json({ error: "Cannot delete Stripe gateway" }, { status: 400 });
    }

    await pool.query(`DELETE FROM admin_payment_gateways WHERE id = $1`, [id]);

    return NextResponse.json({ ok: true });
  } catch (err: any) {
    console.error("[admin/settings/gateways] DELETE Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

"use client";

import { useState, useEffect } from "react";

type Gateway = {
  id: string;
  provider: string;
  display_name: string;
  enabled: boolean;
  mode: "test" | "live";
  priority: number;
  config: Record<string, any>;
  secretKeyConfigured: boolean | null;
  publishableKeyConfigured: boolean | null;
  updated_at: string;
};

type Supplier = {
  id: string;
  provider: string;
  display_name: string;
  enabled: boolean;
  priority: number;
  config: Record<string, any>;
  credentialsConfigured: boolean;
  credentialSource: "db" | "env" | "none";
  customer_number: string | null;
  company_code: string | null;
  warehouse_codes: string[] | null;
  last_test_at: string | null;
  last_test_status: "success" | "error" | null;
  last_test_message: string | null;
  updated_at: string;
};

type SiteSettings = {
  maintenance_mode: boolean;
};

type EmailSettings = {
  enabled: boolean;
  smtpHost: string;
  smtpPort: number;
  smtpUser: string;
  smtpPass: string;
  fromEmail: string;
  fromName: string;
  notifyEmail: string;
  hasPassword?: boolean;
};

export default function SettingsPage() {
  const [gateways, setGateways] = useState<Gateway[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [siteSettings, setSiteSettings] = useState<SiteSettings>({ maintenance_mode: false });
  const [emailSettings, setEmailSettings] = useState<EmailSettings>({
    enabled: false,
    smtpHost: "",
    smtpPort: 587,
    smtpUser: "",
    smtpPass: "",
    fromEmail: "",
    fromName: "Warehouse Tire",
    notifyEmail: "",
  });
  const [loading, setLoading] = useState(true);
  const [needsMigration, setNeedsMigration] = useState(false);
  const [saving, setSaving] = useState<string | null>(null);
  const [testing, setTesting] = useState<string | null>(null);

  const fetchData = async () => {
    try {
      const [gatewaysRes, suppliersRes, settingsRes, emailRes] = await Promise.all([
        fetch("/api/admin/settings/gateways"),
        fetch("/api/admin/settings/suppliers"),
        fetch("/api/admin/settings"),
        fetch("/api/admin/settings/email"),
      ]);

      const gatewaysData = await gatewaysRes.json();
      const suppliersData = await suppliersRes.json();
      const settingsData = await settingsRes.json();
      const emailData = await emailRes.json();

      setGateways(gatewaysData.gateways || []);
      setSuppliers(suppliersData.suppliers || []);
      setSiteSettings(settingsData.settings?.site?.value || { maintenance_mode: false });
      setEmailSettings(emailData);
      setNeedsMigration(gatewaysData.needsMigration || suppliersData.needsMigration);
    } catch (err) {
      console.error("Failed to fetch settings:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const updateGateway = async (gateway: Gateway, updates: Partial<Gateway>) => {
    setSaving(gateway.id);
    try {
      const res = await fetch("/api/admin/settings/gateways", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: gateway.id, provider: gateway.provider, ...updates }),
      });
      if (!res.ok) throw new Error("Failed to save");
      await fetchData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setSaving(null);
    }
  };

  const updateSupplier = async (supplier: Supplier, updates: Partial<Supplier>) => {
    setSaving(supplier.id);
    try {
      const res = await fetch("/api/admin/settings/suppliers", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: supplier.id, provider: supplier.provider, ...updates }),
      });
      if (!res.ok) throw new Error("Failed to save");
      await fetchData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setSaving(null);
    }
  };

  const testSupplier = async (supplier: Supplier) => {
    setTesting(supplier.id);
    try {
      const res = await fetch("/api/admin/settings/suppliers/test", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ provider: supplier.provider }),
      });
      await fetchData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setTesting(null);
    }
  };

  const saveSupplierCredentials = async (provider: string, credentials: Record<string, string>) => {
    try {
      const res = await fetch("/api/admin/settings/suppliers/credentials", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ provider, ...credentials }),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || "Failed to save credentials");
      }
      await fetchData();
    } catch (err: any) {
      alert(err.message);
      throw err;
    }
  };

  const updateSiteSetting = async (key: string, value: any) => {
    setSaving("site");
    try {
      const res = await fetch("/api/admin/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ key: "site", value: { ...siteSettings, [key]: value } }),
      });
      if (!res.ok) throw new Error("Failed to save");
      await fetchData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setSaving(null);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-neutral-500">Loading settings...</div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-white">Settings</h1>
        <p className="text-neutral-400 mt-1">
          Configure payments, email, and site settings
        </p>
      </div>

      {needsMigration && (
        <div className="bg-amber-900/30 border border-amber-700 rounded-lg p-4 text-amber-300">
          <strong>Migration Required:</strong> Run the database migration to enable multi-gateway and multi-supplier support.
          <code className="block mt-2 bg-neutral-800 p-2 rounded text-sm">
            npx drizzle-kit push
          </code>
        </div>
      )}

      {/* Payment Gateways */}
      <section>
        <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
          <span>💳</span> Payment Gateways
        </h2>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          {gateways.map((gateway) => (
            <GatewayCard
              key={gateway.id}
              gateway={gateway}
              saving={saving === gateway.id}
              onUpdate={(updates) => updateGateway(gateway, updates)}
            />
          ))}

          {/* Coming Soon Cards */}
          <ComingSoonCard
            icon="🏦"
            title="Square"
            description="Square payment processing"
          />
          <ComingSoonCard
            icon="🅿️"
            title="PayPal"
            description="PayPal checkout"
          />
        </div>
      </section>

      {/* Site Settings */}
      <section>
        <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
          <span>🌐</span> Site Settings
        </h2>
        <div className="bg-neutral-800 rounded-xl border border-neutral-700 p-6">
          <ToggleSetting
            label="Maintenance Mode"
            description="Show maintenance page to visitors"
            enabled={siteSettings.maintenance_mode}
            saving={saving === "site"}
            danger
            onChange={(enabled) => updateSiteSetting("maintenance_mode", enabled)}
          />
          <div className="mt-4 pt-4 border-t border-neutral-700">
            <div className="text-xs text-neutral-500">
              <strong>Warning:</strong> Enabling maintenance mode will prevent customers
              from accessing the shop.
            </div>
          </div>
        </div>
      </section>

      {/* Email Settings */}
      <section>
        <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
          <span>📧</span> Email Notifications
        </h2>
        <EmailSettingsCard
          settings={emailSettings}
          saving={saving === "email"}
          testing={testing === "email"}
          onSave={async (updates) => {
            setSaving("email");
            try {
              const res = await fetch("/api/admin/settings/email", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(updates),
              });
              if (!res.ok) throw new Error("Failed to save");
              await fetchData();
            } catch (err: any) {
              alert(err.message);
            } finally {
              setSaving(null);
            }
          }}
          onTest={async (toEmail) => {
            setTesting("email");
            try {
              const res = await fetch("/api/admin/settings/email", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ testTo: toEmail }),
              });
              const data = await res.json();
              if (data.ok) {
                alert("Test email sent successfully!");
              } else {
                alert(`Failed: ${data.error}`);
              }
            } catch (err: any) {
              alert(err.message);
            } finally {
              setTesting(null);
            }
          }}
        />
      </section>

      {/* Environment Info */}
      <section className="bg-neutral-800 rounded-xl border border-neutral-700 p-5">
        <h3 className="text-lg font-bold text-white mb-4">Environment</h3>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
          <EnvItem label="Node Env" value={process.env.NODE_ENV || "development"} />
          <EnvItem 
            label="Stripe Key" 
            value={gateways.find(g => g.provider === 'stripe')?.secretKeyConfigured ? "Configured" : "Not set"} 
          />
          <EnvItem label="Database" value="Connected" />
          <EnvItem label="Admin Auth" value="Enabled" />
        </div>
      </section>
    </div>
  );
}

function GatewayCard({
