              >
                Test
              </button>
              <button
                onClick={() => onUpdate({ mode: "live" })}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                  gateway.mode === "live"
                    ? "bg-green-600 text-white"
                    : "bg-neutral-700 text-neutral-300 hover:bg-neutral-600"
