import type pg from "pg";
import { ensureQuoteTables, getSiteSetting, setSiteSetting } from "@/lib/quoteCatalog";

export type PayPalMode = "sandbox" | "live";

export type PayPalSettings = {
  enabled: boolean;
  mode: PayPalMode;
  clientId: string | null;
  /** Stored server-side only; never return this to client code. */
  clientSecretPresent: boolean;
};

const KEYS = {
  enabled: "paypal_enabled",
  mode: "paypal_mode",
  clientId: "paypal_client_id",
  clientSecret: "paypal_client_secret",
} as const;

export async function getPayPalSettings(db: pg.Pool): Promise<PayPalSettings> {
  await ensureQuoteTables(db);
  const enabledRaw = await getSiteSetting(db, KEYS.enabled);
  const modeRaw = (await getSiteSetting(db, KEYS.mode)) as PayPalMode | null;
  const clientId = await getSiteSetting(db, KEYS.clientId);
  const clientSecret = await getSiteSetting(db, KEYS.clientSecret);

  return {
    enabled: enabledRaw === "1" || enabledRaw === "true",
    mode: modeRaw === "live" ? "live" : "sandbox",
    clientId: clientId || null,
    clientSecretPresent: !!(clientSecret && clientSecret.trim().length > 0),
  };
}

export async function setPayPalSettings(
  db: pg.Pool,
  patch: {
    enabled?: boolean;
    mode?: PayPalMode;
    clientId?: string;
    /** Optional: only updates if provided (allows leaving it blank in UI). */
    clientSecret?: string;
  }
) {
  await ensureQuoteTables(db);

  if (typeof patch.enabled === "boolean") {
    await setSiteSetting(db, KEYS.enabled, patch.enabled ? "1" : "0");
  }
  if (patch.mode === "sandbox" || patch.mode === "live") {
    await setSiteSetting(db, KEYS.mode, patch.mode);
  }
  if (typeof patch.clientId === "string") {
    await setSiteSetting(db, KEYS.clientId, patch.clientId.trim());
  }
  if (typeof patch.clientSecret === "string" && patch.clientSecret.trim()) {
    await setSiteSetting(db, KEYS.clientSecret, patch.clientSecret.trim());
  }
}

export async function getPayPalCredentials(db: pg.Pool): Promise<{ clientId: string; clientSecret: string; mode: PayPalMode } | null> {
  await ensureQuoteTables(db);
  const settings = await getPayPalSettings(db);

  if (!settings.enabled || !settings.clientId) return null;

  const clientSecret = await getSiteSetting(db, KEYS.clientSecret);
  if (!clientSecret?.trim()) return null;

  return {
    clientId: settings.clientId,
    clientSecret: clientSecret.trim(),
    mode: settings.mode,
  };
}

import type pg from "pg";
import { getPayPalCredentials, type PayPalMode } from "@/lib/payments/paypalSettings";

const PAYPAL_API = {
  sandbox: "https://api-m.sandbox.paypal.com",
  live: "https://api-m.paypal.com",
} as const;

export type PayPalClient = {
  mode: PayPalMode;
  clientId: string;
  getAccessToken: () => Promise<string>;
  createOrder: (amount: number, currency: string, quoteId: string, description?: string) => Promise<{ id: string; approvalUrl: string }>;
  captureOrder: (orderId: string) => Promise<{ id: string; status: string; payer?: any }>;
};

export async function getPayPalClient(db: pg.Pool): Promise<PayPalClient | null> {
  const creds = await getPayPalCredentials(db);
  if (!creds) return null;

  const baseUrl = PAYPAL_API[creds.mode];

  // Cache access token (they last ~9 hours but we'll refresh more often)
  let cachedToken: { token: string; expiresAt: number } | null = null;

  async function getAccessToken(): Promise<string> {
    // Return cached if still valid (with 5 min buffer)
    if (cachedToken && cachedToken.expiresAt > Date.now() + 300000) {
      return cachedToken.token;
    }

    const auth = Buffer.from(`${creds.clientId}:${creds.clientSecret}`).toString("base64");

    const res = await fetch(`${baseUrl}/v1/oauth2/token`, {
      method: "POST",
      headers: {
        "Authorization": `Basic ${auth}`,
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: "grant_type=client_credentials",
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(`PayPal auth failed: ${res.status} ${text}`);
    }

    const data = await res.json();
    cachedToken = {
      token: data.access_token,
      expiresAt: Date.now() + (data.expires_in || 3600) * 1000,
    };

    return cachedToken.token;
  }

  async function createOrder(
    amount: number,
    currency: string,
    quoteId: string,
    description?: string
  ): Promise<{ id: string; approvalUrl: string }> {
    const token = await getAccessToken();

    const res = await fetch(`${baseUrl}/v2/checkout/orders`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        intent: "CAPTURE",
        purchase_units: [
          {
            reference_id: quoteId,
            description: description || "Warehouse Tire Order",
            amount: {
              currency_code: currency.toUpperCase(),
              value: amount.toFixed(2),
            },
            custom_id: quoteId,
          },
        ],
        application_context: {
          brand_name: "Warehouse Tire",
          shipping_preference: "NO_SHIPPING", // We collect shipping ourselves
          user_action: "PAY_NOW",
        },
      }),
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(`PayPal create order failed: ${res.status} ${text}`);
    }

    const data = await res.json();
    const approvalLink = data.links?.find((l: any) => l.rel === "approve");

    if (!approvalLink?.href) {
      throw new Error("PayPal order created but no approval URL found");
    }

    return {
      id: data.id,
      approvalUrl: approvalLink.href,
    };
  }

  async function captureOrder(orderId: string): Promise<{ id: string; status: string; payer?: any }> {
    const token = await getAccessToken();

    const res = await fetch(`${baseUrl}/v2/checkout/orders/${orderId}/capture`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${token}`,
        "Content-Type": "application/json",
      },
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(`PayPal capture failed: ${res.status} ${text}`);
    }

    const data = await res.json();
    return {
      id: data.id,
      status: data.status,
      payer: data.payer,
    };
  }

  return {
    mode: creds.mode,
    clientId: creds.clientId,
    getAccessToken,
    createOrder,
    captureOrder,
  };
}

