    const items: CartItem[] = Array.isArray(body.items) ? body.items : [];

    const customer = body.customer && typeof body.customer === "object" ? body.customer : {};
    const firstName = String(customer.firstName || "").trim();
    const lastName = String(customer.lastName || "").trim();
    const email = String(customer.email || "").trim();
    const phone = String(customer.phone || "").trim();

    if (!firstName || !lastName) {
      return NextResponse.json({ ok: false, error: "name_required" }, { status: 400 });
    }
    if (!email && !phone) {
      return NextResponse.json({ ok: false, error: "email_or_phone_required" }, { status: 400 });
    }

    const vehicle = body.vehicle && typeof body.vehicle === "object" ? body.vehicle : undefined;

    // Convert cart items to quote lines
    const linesAll: QuoteLine[] = items
      .map((i: any) => {
        const kind: QuoteLine["kind"] = "product";
        const name = String(i.model || i.name || i.sku || "Item").trim();
        const sku = String(i.sku || "").trim() || undefined;
        const unitPriceUsd = Number(i.unitPrice || 0);
        const qty = Math.max(1, Math.trunc(Number(i.quantity || 1)));
        const taxable = i.type === "wheel" || i.type === "tire";

        const meta = {
          cartType: i.type,
          category: i.category,
          required: !!i.required,
          wheelSku: i.wheelSku,
          spec: i.spec,
          meta: i.meta,
        };

        return { kind, name, sku, unitPriceUsd, qty, taxable, meta };
      })
      .filter((l) => l.qty > 0);

    if (linesAll.length === 0) {
      return NextResponse.json({ ok: false, error: "empty_cart" }, { status: 400 });
    }

    // Calculate total (only billable items)
    const billableLines = linesAll.filter((l) => l.unitPriceUsd > 0);
    if (billableLines.length === 0) {
      return NextResponse.json(
        { ok: false, error: "no_billable_items" },
        { status: 400 }
      );
    }

    const totalAmount = billableLines.reduce((sum, l) => sum + l.unitPriceUsd * l.qty, 0);

    const db = getPool();
    const paypal = await getPayPalClient(db);
    if (!paypal) {
      return NextResponse.json({ ok: false, error: "paypal_not_configured" }, { status: 400 });
    }

    // Create quote first
    const { id: quoteId } = await createQuote(db, {
      customer: { firstName, lastName, email: email || undefined, phone: phone || undefined },
      vehicle,
      lines: linesAll,
    });

    // Create PayPal order
    const vehicleDesc = vehicle
      ? `${vehicle.year} ${vehicle.make} ${vehicle.model}`
      : undefined;
    const description = vehicleDesc
      ? `Tires & Wheels for ${vehicleDesc}`
      : "Tires & Wheels Order";

    const order = await paypal.createOrder(totalAmount, "USD", quoteId, description);

    return NextResponse.json({
      ok: true,
      orderId: order.id,
      approvalUrl: order.approvalUrl,
      quoteId,
    });
  } catch (e: any) {
    console.error("[paypal/create-order] Error:", e);
    return NextResponse.json({ ok: false, error: e?.message || String(e) }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { getPool } from "@/lib/quotes";
import { getPayPalClient } from "@/lib/payments/paypalClient";

export const runtime = "nodejs";

export async function POST(req: Request) {
  try {
    const body = await req.json().catch(() => ({} as any));
    const orderId = String(body.orderId || "").trim();

    if (!orderId) {
      return NextResponse.json({ ok: false, error: "orderId_required" }, { status: 400 });
    }

    const db = getPool();
    const paypal = await getPayPalClient(db);
    if (!paypal) {
      return NextResponse.json({ ok: false, error: "paypal_not_configured" }, { status: 400 });
    }

    const result = await paypal.captureOrder(orderId);

    if (result.status !== "COMPLETED") {
      return NextResponse.json({
        ok: false,
        error: "capture_not_completed",
        status: result.status,
      }, { status: 400 });
    }

    // TODO: Update quote/order status in database
    // For now, just return success - the success page will handle display

    return NextResponse.json({
      ok: true,
      orderId: result.id,
      status: result.status,
      payer: result.payer,
    });
  } catch (e: any) {
    console.error("[paypal/capture-order] Error:", e);
    return NextResponse.json({ ok: false, error: e?.message || String(e) }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import pg from "pg";
import { getPayPalSettings, setPayPalSettings, type PayPalMode } from "@/lib/payments/paypalSettings";

export const runtime = "nodejs";

const { Pool } = pg;

function getPool() {
  const url = process.env.DATABASE_URL || process.env.POSTGRES_URL;
  if (!url) throw new Error("Missing DATABASE_URL");
  return new Pool({
    connectionString: url,
    ssl: { rejectUnauthorized: false },
    max: 3,
  });
}

/**
 * Get PayPal settings (safe for client - no secrets)
 */
export async function GET() {
  const pool = getPool();
  try {
    const settings = await getPayPalSettings(pool);
    return NextResponse.json({
      enabled: settings.enabled,
      mode: settings.mode,
      clientId: settings.clientId,
      clientSecretPresent: settings.clientSecretPresent,
    });
  } catch (err: any) {
    console.error("[admin/settings/paypal] GET Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

/**
 * Update PayPal settings
 */
export async function POST(req: Request) {
  const body = await req.json();
  const { enabled, mode, clientId, clientSecret } = body;

  const pool = getPool();
  try {
    await setPayPalSettings(pool, {
      enabled: typeof enabled === "boolean" ? enabled : undefined,
      mode: mode === "sandbox" || mode === "live" ? (mode as PayPalMode) : undefined,
      clientId: typeof clientId === "string" ? clientId : undefined,
      clientSecret: typeof clientSecret === "string" ? clientSecret : undefined,
    });

    // Log the change
    try {
      await pool.query(`
        INSERT INTO admin_logs (log_type, details)
        VALUES ('paypal_settings_update', $1)
      `, [JSON.stringify({ enabled, mode, clientIdSet: !!clientId, secretSet: !!clientSecret })]);
    } catch (logErr) {
      // Ignore log errors
    }

    const updated = await getPayPalSettings(pool);
    return NextResponse.json({
      ok: true,
      enabled: updated.enabled,
      mode: updated.mode,
      clientId: updated.clientId,
      clientSecretPresent: updated.clientSecretPresent,
    });
  } catch (err: any) {
    console.error("[admin/settings/paypal] POST Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  } finally {
    await pool.end();
  }
}

